import React, { useState } from 'react';

const JobListContainer = ({ appTheme = 'dark', limit }) => {
    // Data dummy yang lebih lengkap
    const [jobs] = useState([
        { id: 1, title: 'Fullstack Developer', company: 'PasukanYerusSolo', location: 'Solo (Remote)', salary: 'Rp 8.000.000', type: 'Full-time', category: 'IT', desc: 'Membangun arsitektur web modern menggunakan React & Laravel.' },
        { id: 2, title: 'React Frontend Engineer', company: 'TechEase Indonesia', location: 'Jakarta', salary: 'Rp 12.000.000', type: 'Remote', category: 'IT', desc: 'Fokus pada pengembangan antarmuka interaktif dan responsif.' },
        { id: 3, title: 'Marketing Specialist', company: 'Solopos Group', location: 'Solo', salary: 'Rp 6.500.000', type: 'Full-time', category: 'Marketing', desc: 'Mengelola kampanye digital dan strategi pertumbuhan brand.' },
        { id: 4, title: 'Admin Operasional', company: 'Logistik Solo', location: 'Solo', salary: 'Rp 4.500.000', type: 'Contract', category: 'Administrasi', desc: 'Manajemen dokumentasi dan dukungan operasional harian.' }
    ]);

    const [filter, setFilter] = useState('Semua');
    const displayJobs = (filter === 'Semua' ? jobs : jobs.filter(j => j.category === filter))
                        .slice(0, limit || jobs.length);

    const colors = { cardBg: '#120b06', border: '1px solid #262626', textMain: '#fef3c7', accent: '#ea580c', textMuted: '#a3a3a3' };

    return (
        <div style={{ padding: '20px', background: '#080402', minHeight: '80vh' }}>
            {/* Header & Filter */}
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '30px', alignItems: 'center' }}>
                <h2 style={{ color: colors.textMain, fontSize: '24px' }}>Daftar Lowongan</h2>
                <select onChange={(e) => setFilter(e.target.value)} style={{ background: colors.cardBg, color: colors.textMain, padding: '8px', borderRadius: '8px', border: colors.border }}>
                    <option value="Semua">Semua Kategori</option>
                    <option value="IT">IT</option>
                    <option value="Marketing">Marketing</option>
                    <option value="Administrasi">Administrasi</option>
                </select>
            </div>

            {/* List Lowongan */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '20px' }}>
                {displayJobs.map(job => (
                    <div key={job.id} style={{ padding: '24px', background: colors.cardBg, border: colors.border, borderRadius: '16px', transition: '0.3s' }}>
                        <h3 style={{ color: colors.textMain, fontSize: '18px', marginBottom: '8px' }}>{job.title}</h3>
                        <p style={{ color: colors.accent, fontSize: '14px', marginBottom: '12px', fontWeight: 'bold' }}>{job.company}</p>
                        <div style={{ display: 'flex', gap: '10px', fontSize: '12px', color: colors.textMuted, marginBottom: '15px' }}>
                            <span>📍 {job.location}</span>
                            <span>💰 {job.salary}</span>
                        </div>
                        <p style={{ color: colors.textMuted, fontSize: '13px', lineHeight: '1.6', marginBottom: '20px' }}>{job.desc}</p>
                        <button style={{ width: '100%', padding: '10px', background: colors.accent, border: 'none', borderRadius: '8px', color: '#fff', fontWeight: 'bold', cursor: 'pointer' }}>
                            Detail & Lamar
                        </button>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default JobListContainer;
